import {
  forwardRef,
  Fragment,
  type HTMLAttributes,
  type ReactNode,
  useEffect,
  useRef,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { SkeletonItem } from './SkeletonItem';

export interface SkeletonProps extends Omit<HTMLAttributes<HTMLDivElement>, 'children'> {
  /** Whether to show the placeholder. When false, `children` are rendered. */
  loading?: boolean;
  /** Number of text rows in the default template. */
  rows?: number;
  /** Enable the shimmer animation. */
  animated?: boolean;
  /** Repeat the placeholder template this many times. */
  count?: number;
  /** Delay (ms) before the placeholder appears, avoiding flashes on fast loads. */
  throttle?: number;
  /** Real content, shown once `loading` is false. */
  children?: ReactNode;
}

export const Skeleton = forwardRef<HTMLDivElement, SkeletonProps>(function Skeleton(props, ref) {
  const {
    loading = true,
    rows = 3,
    animated = false,
    count = 1,
    throttle,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('skeleton');

  // When `throttle` is set, defer showing the placeholder until the delay
  // elapses so brief loads do not flash a skeleton.
  const [throttled, setThrottled] = useState(throttle != null && throttle > 0);
  const timer = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);

  useEffect(() => {
    if (throttle == null || throttle <= 0) {
      setThrottled(false);
      return;
    }
    if (loading) {
      setThrottled(true);
      timer.current = setTimeout(() => setThrottled(false), throttle);
    }
    return () => {
      if (timer.current) clearTimeout(timer.current);
    };
  }, [throttle, loading]);

  const showPlaceholder = loading && !throttled;

  const classes = cls(ns.b(), ns.is('animated', animated), className);

  if (!showPlaceholder) {
    return (
      <div ref={ref} className={classes} {...rest}>
        {children}
      </div>
    );
  }

  const templates = Array.from({ length: Math.max(count, 1) }, (_, i) => (
    <Fragment key={i}>
      <div className={ns.e('template')}>
        <SkeletonItem variant="h3" style={{ width: '50%' }} />
        {Array.from({ length: Math.max(rows, 0) }, (_, row) => (
          <SkeletonItem
            key={row}
            variant="text"
            // The last row is intentionally shorter to mimic real prose.
            style={row === rows - 1 ? { width: '60%' } : undefined}
          />
        ))}
      </div>
    </Fragment>
  ));

  return (
    <div ref={ref} className={classes} aria-busy="true" aria-live="polite" {...rest}>
      {templates}
    </div>
  );
});

import { forwardRef, type HTMLAttributes } from 'react';
import { cls, useNamespace } from '../../utils';

export type SkeletonVariant =
  | 'p'
  | 'text'
  | 'h1'
  | 'h3'
  | 'caption'
  | 'button'
  | 'image'
  | 'circle'
  | 'rect';

export interface SkeletonItemProps extends HTMLAttributes<HTMLDivElement> {
  /** Shape of the placeholder. */
  variant?: SkeletonVariant;
}

export const SkeletonItem = forwardRef<HTMLDivElement, SkeletonItemProps>(function SkeletonItem(
  props,
  ref,
) {
  const { variant = 'text', className, ...rest } = props;
  const ns = useNamespace('skeleton');

  return (
    <div ref={ref} className={cls(ns.e('item'), ns.m(variant), className)} {...rest} />
  );
});

.ec-skeleton {
  --ec-skeleton-color: var(--ec-fill-color);
  --ec-skeleton-to-color: var(--ec-fill-color-darker);

  width: 100%;
}

.ec-skeleton__template {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.ec-skeleton__template + .ec-skeleton__template {
  margin-top: 16px;
}

.ec-skeleton__item {
  display: inline-block;
  box-sizing: border-box;
  width: 100%;
  height: 16px;
  background: var(--ec-skeleton-color);
  border-radius: var(--ec-border-radius-base);
}

/* ---- Variants ---- */
.ec-skeleton__item.ec-skeleton--p,
.ec-skeleton__item.ec-skeleton--text {
  width: 100%;
  height: 16px;
}

.ec-skeleton__item.ec-skeleton--h1 {
  height: 28px;
}

.ec-skeleton__item.ec-skeleton--h3 {
  height: 18px;
}

.ec-skeleton__item.ec-skeleton--caption {
  height: 12px;
}

.ec-skeleton__item.ec-skeleton--button {
  width: 64px;
  height: var(--ec-component-size);
  border-radius: var(--ec-border-radius-base);
}

.ec-skeleton__item.ec-skeleton--image {
  width: 100%;
  height: 100px;
  border-radius: 0;
}

.ec-skeleton__item.ec-skeleton--rect {
  width: 100%;
  height: 100%;
}

.ec-skeleton__item.ec-skeleton--circle {
  width: var(--ec-component-size);
  height: var(--ec-component-size);
  border-radius: var(--ec-border-radius-circle);
}

/* ---- Animation ---- */
.ec-skeleton.is-animated .ec-skeleton__item {
  background: linear-gradient(
    90deg,
    var(--ec-skeleton-color) 25%,
    var(--ec-skeleton-to-color) 37%,
    var(--ec-skeleton-color) 63%
  );
  background-size: 400% 100%;
  animation: ec-skeleton-shimmer 1.4s ease infinite;
}

@keyframes ec-skeleton-shimmer {
  0% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0 50%;
  }
}
